	@Test
	void subSelectPlanDoesNotDoubleCountRepeatedDirectLookupRows() {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			TupleExpr tupleExpr = (TupleExpr) connection.prepareTupleQuery(SUB_SELECT)
					.explain(Explanation.Level.Optimized)
					.tupleExpr();
			List<String> offenders = new ArrayList<>();
			tupleExpr.visit(new AbstractSimpleQueryModelVisitor<RuntimeException>() {
				@Override
				public void meet(Join node) {
					if (node.getRightArg()instanceof StatementPattern rightPattern
							&& "directLookup".equals(rightPattern
									.getStringMetricPlanned(TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE))) {
						double joinRows = node.getResultSizeEstimate();
						double rightRows = rightPattern.getResultSizeEstimate();
						double accessRows = rightPattern
								.getDoubleMetricPlanned(TelemetryMetricNames.PLANNED_ACCESS_ROWS);
						if (Double.isFinite(joinRows) && Double.isFinite(rightRows) && rightRows > 0.0d
								&& Double.isFinite(accessRows) && accessRows <= 1.0d
								&& joinRows > rightRows * 100.0d) {
							offenders.add("joinRows=" + joinRows + ", rightRows=" + rightRows + ", accessRows="
									+ accessRows + ", right=" + rightPattern);
						}
					}
					super.meet(node);
				}
			});
			assertTrue(offenders.isEmpty(), offenders.toString());
			assertNoUnboundedTypeTypeCrossProduct(tupleExpr);
			assertNoTypeFilterBeforeDatasetBridge(tupleExpr);
		}
	}

